import { useEffect, useState } from "react";
import api from "../api/client";
import { useAuth } from "../context/AuthContext";

const WorkspacePage = () => {
  const { user } = useAuth();
  const [projects, setProjects] = useState([]);
  const [tasks, setTasks] = useState([]);
  const [projectForm, setProjectForm] = useState({ name: "", description: "" });
  const [taskForm, setTaskForm] = useState({ title: "", description: "", projectId: "", assignedTo: "", dueDate: "" });
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  const loadData = async () => {
    const [projectRes, taskRes] = await Promise.all([api.get("/projects"), api.get("/tasks")]);
    setProjects(projectRes.data);
    setTasks(taskRes.data);
  };

  useEffect(() => {
    loadData();
  }, []);

  const createProject = async (e) => {
    e.preventDefault();
    setError("");
    setSuccess("");
    try {
      await api.post("/projects", { ...projectForm, teamMembers: [user.id] });
      setProjectForm({ name: "", description: "" });
      setSuccess("Project created successfully");
      loadData();
    } catch (err) {
      setError(err.response?.data?.message || "Failed to create project");
    }
  };

  const createTask = async (e) => {
    e.preventDefault();
    setError("");
    setSuccess("");
    try {
      await api.post("/tasks", taskForm);
      setTaskForm({ title: "", description: "", projectId: "", assignedTo: "", dueDate: "" });
      setSuccess("Task created successfully");
      loadData();
    } catch (err) {
      setError(err.response?.data?.message || "Failed to create task");
    }
  };

  const updateStatus = async (taskId, status) => {
    setError("");
    setSuccess("");
    try {
      await api.patch(`/tasks/${taskId}/status`, { status });
      setSuccess("Task status updated");
      loadData();
    } catch (err) {
      setError(err.response?.data?.message || "Failed to update task");
    }
  };

  return (
    <div className="grid">
      <div className="card id-help-card">
        <h2>Your User ID</h2>
        <p className="id-help-text">
          Use this ID when you need to assign tasks manually.
        </p>
        <code className="id-code">{user.id}</code>
      </div>

      {error ? <p className="error-text">{error}</p> : null}
      {success ? <p className="success-text">{success}</p> : null}

      {user.role === "Admin" && (
        <div className="card">
          <h2>Create Project</h2>
          <form onSubmit={createProject}>
            <label>Project Name</label>
            <input value={projectForm.name} onChange={(e) => setProjectForm((p) => ({ ...p, name: e.target.value }))} required />
            <label>Description</label>
            <textarea value={projectForm.description} onChange={(e) => setProjectForm((p) => ({ ...p, description: e.target.value }))} />
            <button type="submit">Create Project</button>
          </form>
        </div>
      )}

      <div className="card">
        <h2>Create Task</h2>
        <form onSubmit={createTask}>
          <label>Title</label>
          <input value={taskForm.title} onChange={(e) => setTaskForm((p) => ({ ...p, title: e.target.value }))} required />
          <label>Description</label>
          <textarea value={taskForm.description} onChange={(e) => setTaskForm((p) => ({ ...p, description: e.target.value }))} />
          <label>Project</label>
          <select value={taskForm.projectId} onChange={(e) => setTaskForm((p) => ({ ...p, projectId: e.target.value }))} required>
            <option value="">Select project</option>
            {projects.map((p) => (
              <option key={p._id} value={p._id}>{p.name}</option>
            ))}
          </select>
          <label>Assign To (User ID)</label>
          <input value={taskForm.assignedTo} onChange={(e) => setTaskForm((p) => ({ ...p, assignedTo: e.target.value }))} required />
          <small className="hint-text">Assignee must already be a member of the selected project.</small>
          <label>Due Date</label>
          <input type="date" value={taskForm.dueDate} onChange={(e) => setTaskForm((p) => ({ ...p, dueDate: e.target.value }))} required />
          <button type="submit">Create Task</button>
        </form>
      </div>

      <div className="card">
        <h2>My Tasks</h2>
        {tasks.map((task) => (
          <div key={task._id} className="card task-card">
            <h3>{task.title}</h3>
            <p className="task-meta">Status: <strong>{task.status}</strong></p>
            <p>Project: {task.project?.name || "N/A"}</p>
            <select value={task.status} onChange={(e) => updateStatus(task._id, e.target.value)}>
              <option value="Todo">Todo</option>
              <option value="In Progress">In Progress</option>
              <option value="Done">Done</option>
            </select>
          </div>
        ))}
      </div>
    </div>
  );
};

export default WorkspacePage;
